(1258640, '698a2ed354410c000732dc93', 'assistant', 'Disculpa, no logré capturar tu correo electrónico completo. \n\n¿Podrías proporcionarme tu correo electrónico completo nuevamente, por favor? Por ejemplo: nombre.apellido@empresa.com.mx', '2026-02-09 13:05:57', 0, NULL),
(1359358, '698c9458a993cc0007f3692c', 'assistant', 'Excelente, he validado tu correo electrónico exitosamente. \n\n**Expendio Region 75**, confirmo que tu correo **expendio.region75@keken.com.mx** está registrado en nuestro sistema.\n\n¿Confirmas que este es tu correo correcto?', '2026-02-11 08:39:15', 0, NULL),
