(2652134, '69288b1765949e7acf6d0606', 'user', 'hola', '2025-11-27 17:33:27', 0, NULL),
(2652135, '69288b1765949e7acf6d0606', 'assistant', '¡Hola! Es un gusto saludarte. Soy tu agente virtual de service desk y estoy aquí para ayudarte con cualquier consulta que tengas.\n\n¿En qué puedo asistirte el día de hoy? Puedo ayudarte con información sobre procesos, desbloqueo de usuarios, cambio de contraseñas, crear tickets de soporte, o cualquier otra consulta relacionada con nuestros servicios.', '2025-11-27 17:33:32', 0, NULL),
