(2652713, '69a710792edc830007fba16f', 'assistant', 'Los datos con los que se generó el ticket son los siguientes:\n\n\nNúmero de ticket: 6 2 2 9 5 6 .\nEstatus: Abierto \nLe recuerdo los datos de su ticket:Número de ticket: 6 2 2 9 5 6 .Estatus: Abierto', '2026-03-03 16:49:15', 0, NULL),
(2652954, '69a6064c453a240007dc33e1', 'assistant', 'Gracias por tu respuesta. Para poder validar tu correo correctamente, necesito que me proporciones el correo completo, incluyendo la parte antes del @gmail.com. \n\nPor ejemplo: tunombre@gmail.com\n\n¿Podrías compartirme tu correo electrónico completo, por favor?', '2026-03-02 21:51:28', 0, NULL),
