(2651680, '69962c23a92ff4779ec890e5', 'assistant', 'Hola, veo que me has saludado nuevamente. \n\n¿Tienes alguna consulta específica o necesitas ayuda con algo en particular? Estoy aquí para asistirte con cualquier pregunta o problema que tengas.', '2026-02-18 22:46:19', 0, NULL),
